const posts = $input.all().map(i => i.json);
const platform = $('Webhook — Schedule Content').first().json.body?.platform || 'tiktok';

// Analyze posting times vs engagement
const hourEngagement = {};
for (const p of posts) {
  try {
    const postedAt = p.properties?.PostedAt?.date?.start;
    if (!postedAt) continue;
    const hour = new Date(postedAt).getUTCHours();
    const score = p.properties?.PerformanceScore?.number || 0;
    if (!hourEngagement[hour]) hourEngagement[hour] = { total: 0, count: 0 };
    hourEngagement[hour].total += score;
    hourEngagement[hour].count++;
  } catch(e) {}
}

// Find best hours
const bestHours = Object.entries(hourEngagement)
  .map(([h, v]) => ({ hour: parseInt(h), avgScore: v.total / v.count }))
  .sort((a, b) => b.avgScore - a.avgScore)
  .slice(0, 3)
  .map(h => h.hour);

// Default best hours per platform if no data
const defaults = {
  tiktok: [7, 19, 21],
  youtube: [14, 17, 20],
  instagram: [8, 11, 19]
};
const optimalHours = bestHours.length >= 2 ? bestHours : (defaults[platform.toLowerCase()] || [12, 18, 20]);

// Schedule for next optimal hour
const now = new Date();
let scheduledTime = new Date(now);
scheduledTime.setMinutes(0, 0, 0);

for (let i = 1; i <= 48; i++) {
  scheduledTime = new Date(now.getTime() + i * 3600000);
  if (optimalHours.includes(scheduledTime.getUTCHours())) break;
}

return [{
  json: {
    contentId: $('Webhook — Schedule Content').first().json.body?.contentId,
    platform: platform,
    scheduledTime: scheduledTime.toISOString(),
    optimalHours,
    title: $('Webhook — Schedule Content').first().json.body?.title || 'Scheduled Content',
    videoUrl: $('Webhook — Schedule Content').first().json.body?.videoUrl || ''
  }
}];
